import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.*;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.client.RestTemplate;
 
@CrossOrigin(origins = "*") // Allow all origins for testing purposes only, in a production setting you should restrict this to specific allowed domains or IPs using CORS filters and/or security configurations like JWT tokens etc..
public class WebhookHandler {
    @Autowired 
    private RestTemplate restTemplate;  
    
    // Method for handling web hook requests from partner APIs. This method fetches content, processes it (if necessary) using a REST template and returns the response back to client application or user interface via HTTP status code/headers etc..     
       @PostMapping("/webhook") 
        public ResponseEntity<String> handleWebHook(@RequestBody String url){  
            HttpHeaders headers = new HttpHeaders();     // Set content type as JSON for REST template.   
             headers.setContentType(MediaType.APPLICATION_JSON);     
             
           try { 
               ResponseEntity<String> response =  restTemplate.getForEntity(url, String.class );  
                if (response.getStatusCodeValue() == 200)    // If HTTP status code is OK then return the content of webhook request otherwise throw exception..     
                    return new ResponseEntity<>("Successfully fetched data from URL: " + url , headers, HttpStatus.OK);  
                else 
                  throw new Exception ("Failed to fetch Data From Url :"+url );    // Throw an error if HTTP status code is not OK..     
            } catch (Exception e) {     // Catch any exception and return appropriate response back via http headers etc.      
               return new ResponseEntity<>(e.getMessage(),headers, HttpStatus.INTERNAL_SERVER_ERROR); 
           }   
        }  
}